import React, { useState, useEffect, useContext } from "react";
import { AuthContext } from "../../context/AuthContext";

const AdminUsers = () => {
  const { user: currentUser } = useContext(AuthContext);

  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  // Popup chỉnh sửa
  const [editUser, setEditUser] = useState(null);
  const [editName, setEditName] = useState("");
  const [editRole, setEditRole] = useState("user");

  // Tìm kiếm & phân trang
  const [searchTerm, setSearchTerm] = useState("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalUsers, setTotalUsers] = useState(0);

  useEffect(() => {
    fetchUsers(page, searchTerm);
    // eslint-disable-next-line
  }, [page]);

  // ==================================================
  // 📌 LẤY DANH SÁCH NGƯỜI DÙNG (CÓ TÌM KIẾM + PHÂN TRANG)
  // ==================================================
  const fetchUsers = async (pageNumber = 1, search = "") => {
    try {
      setLoading(true);

      const storedUser = JSON.parse(localStorage.getItem("userInfo"));
      const token =
        storedUser?.accessToken ||
        storedUser?.token ||
        storedUser?.user?.accessToken;

      if (!token) {
        setError("Không tìm thấy phiên đăng nhập. Hãy đăng nhập lại.");
        return;
      }

      let url = `http://localhost:5000/api/admin/users?page=${pageNumber}&limit=10`;
      if (search) url += `&search=${encodeURIComponent(search)}`;

      const res = await fetch(url, {
        headers: { Authorization: `Bearer ${token}` },
      });

      const data = await res.json();

      if (data.success && Array.isArray(data.data)) {
        setUsers(data.data);
        setPage(data.page || 1);
        setTotalPages(data.pages || 1);
        setTotalUsers(data.total || 0);
      } else {
        setError("Dữ liệu trả về không hợp lệ.");
      }
    } catch (err) {
      console.error(err);
      setError("Không thể kết nối đến máy chủ.");
    } finally {
      setLoading(false);
    }
  };

  // ==================================================
  // 📌 MỞ POPUP SỬA NGƯỜI DÙNG
  // ==================================================
  const openEditModal = (u) => {
    setEditUser(u);
    setEditName(u.name);
    setEditRole(u.role);
  };

  // ==================================================
  // 📌 CẬP NHẬT THÔNG TIN NGƯỜI DÙNG
  // ==================================================
  const handleUpdate = async () => {
    const storedUser = JSON.parse(localStorage.getItem("userInfo"));
    const token = storedUser?.accessToken;

    if (!token) return alert("Bạn chưa đăng nhập!");

    try {
      const res = await fetch(
        `http://localhost:5000/api/admin/users/${editUser._id}`,
        {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
          body: JSON.stringify({
            name: editName,
            role: editRole,
          }),
        }
      );

      const data = await res.json();

      if (data.success) {
        alert("Cập nhật thành công!");
        setEditUser(null);
        fetchUsers(page, searchTerm);
      }
    } catch (err) {
      console.error(err);
      alert("Lỗi khi cập nhật thông tin người dùng");
    }
  };

  // ==================================================
  // 📌 KHÓA / MỞ KHÓA NGƯỜI DÙNG
  // ==================================================
  const toggleActive = async (id) => {
    const storedUser = JSON.parse(localStorage.getItem("userInfo"));
    const token = storedUser?.accessToken;

    if (!token) return alert("Bạn chưa đăng nhập!");

    try {
      const res = await fetch(
        `http://localhost:5000/api/admin/users/${id}/toggle`,
        {
          method: "PATCH",
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      const data = await res.json();
      if (data.success) {
        alert(data.message);
        fetchUsers(page, searchTerm);
      }
    } catch (err) {
      console.error(err);
      alert("Lỗi khi khoá/mở khoá người dùng");
    }
  };

  // ==================================================
  // 📌 ĐẶT LẠI MẬT KHẨU
  // ==================================================
  const handleResetPassword = async (id) => {
    if (!window.confirm("Bạn có chắc muốn đặt lại mật khẩu về 123456?"))
      return;

    const storedUser = JSON.parse(localStorage.getItem("userInfo"));
    const token = storedUser?.accessToken;

    try {
      const res = await fetch(
        `http://localhost:5000/api/admin/users/${id}/reset-mat-khau`,
        {
          method: "POST",
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      const data = await res.json();
      if (data.success) {
        alert(`Mật khẩu mới là: ${data.matKhauMoi}`);
      }
    } catch (err) {
      console.error(err);
      alert("Lỗi khi đặt lại mật khẩu");
    }
  };

  // ==================================================
  // 📌 XOÁ NGƯỜI DÙNG
  // ==================================================
  const handleDeleteUser = async (id) => {
    if (!window.confirm("Bạn có chắc muốn xoá người dùng này?")) return;

    const storedUser = JSON.parse(localStorage.getItem("userInfo"));
    const token = storedUser?.accessToken;

    try {
      const res = await fetch(
        `http://localhost:5000/api/admin/users/${id}`,
        {
          method: "DELETE",
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      const data = await res.json();
      if (data.success) {
        alert("Đã xoá người dùng");
        fetchUsers(page, searchTerm);
      }
    } catch (err) {
      console.error(err);
      alert("Lỗi khi xoá người dùng");
    }
  };

  // Format ngày tháng
  const formatDate = (date) =>
    new Date(date).toLocaleDateString("vi-VN", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
    });

  // Badge vai trò
  const getRoleBadge = (role) => {
    const styles = {
      admin: "bg-[#ffe6e9] text-[#c85b70]",
      user: "bg-[#f1e4da] text-[#8b5e3c]",
    };

    return (
      <span
        className={`px-3 py-1 text-xs rounded-full ${styles[role] || styles.user}`}
      >
        {role === "admin" ? "Quản trị viên" : "Người dùng"}
      </span>
    );
  };

  // ==================================================
  // 📌 GIAO DIỆN
  // ==================================================
  return (
    <div className="min-h-screen bg-white text-[#2c2c2c] font-sans">

      <h2 className="text-2xl font-semibold flex items-center gap-2 mb-8">
        <span className="text-[#e06c7f]">👤</span> Quản lý người dùng
      </h2>

      {/* Hiện lỗi */}
      {error && (
        <div className="bg-[#ffe6e9] text-[#c85b70] px-4 py-3 rounded mb-4">
          {error}
        </div>
      )}

      {/* Đang tải */}
      {loading ? (
        <div className="flex justify-center py-10">
          <div className="animate-spin rounded-full h-10 w-10 border-t-2 border-b-2 border-[#e06c7f]"></div>
        </div>
      ) : (
        <>
          {/* Thanh tìm kiếm */}
          <div className="flex flex-col md:flex-row md:items-center md:justify-between mb-6 gap-3">
            <p className="text-sm text-[#8b5e3c]">
              Tổng cộng: <b>{totalUsers}</b> người dùng
            </p>

            <div className="flex items-center gap-2">
              <input
                type="text"
                placeholder="Tìm theo tên hoặc email..."
                className="border border-[#f1e4da] rounded px-3 py-2 text-sm focus:ring-[#e06c7f]"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && fetchUsers(1, searchTerm)}
              />

              <button
                onClick={() => fetchUsers(1, searchTerm)}
                className="px-4 py-2 bg-[#e06c7f] text-white rounded hover:bg-[#c85b70]"
              >
                Tìm
              </button>
            </div>
          </div>

          {/* Bảng người dùng */}
          <div className="bg-white border border-[#f1e4da] rounded-lg shadow-sm overflow-hidden">
            <table className="min-w-full text-sm">
              <thead className="bg-[#faf8f6] border-b border-[#f1e4da]">
                <tr>
                  <th className="px-6 py-3 text-left">Tên</th>
                  <th className="px-6 py-3 text-left">Email</th>
                  <th className="px-6 py-3 text-left">Vai trò</th>
                  <th className="px-6 py-3 text-left">Ngày tạo</th>
                  <th className="px-6 py-3 text-left">Thao tác</th>
                </tr>
              </thead>

              <tbody>
                {users.map((u) => (
                  <tr key={u._id} className="hover:bg-[#faf8f6]">
                    <td className="px-6 py-4">{u.name}</td>
                    <td className="px-6 py-4">{u.email}</td>
                    <td className="px-6 py-4">{getRoleBadge(u.role)}</td>
                    <td className="px-6 py-4">{formatDate(u.createdAt)}</td>

                    <td className="px-6 py-4 flex gap-3">

                      {u._id === currentUser?._id ? (
                        <span className="text-gray-400">Tài khoản hiện tại</span>
                      ) : (
                        <>
                          <button
                            onClick={() => openEditModal(u)}
                            className="text-[#8b5e3c] hover:text-[#e06c7f]"
                          >
                            Sửa
                          </button>

                          <button
                            onClick={() => toggleActive(u._id)}
                            className="text-[#e06c7f] hover:text-[#c85b70]"
                          >
                            {u.active ? "Khoá" : "Mở khoá"}
                          </button>

                          <button
                            onClick={() => handleResetPassword(u._id)}
                            className="text-[#4b7bec] hover:text-[#3867d6]"
                          >
                            Đặt lại mật khẩu
                          </button>

                          <button
                            onClick={() => handleDeleteUser(u._id)}
                            className="text-red-500 hover:text-red-700"
                          >
                            Xoá
                          </button>
                        </>
                      )}

                    </td>
                  </tr>
                ))}
              </tbody>
            </table>

            {/* Phân trang */}
            <div className="flex items-center justify-between px-6 py-4 border-t border-[#f1e4da]">
              <button
                disabled={page <= 1}
                onClick={() => setPage(page - 1)}
                className={`px-3 py-1 rounded border ${
                  page <= 1
                    ? "text-gray-300 border-gray-200 cursor-not-allowed"
                    : "text-[#8b5e3c] border-[#f1e4da] hover:bg-[#faf8f6]"
                }`}
              >
                « Trang trước
              </button>

              <span className="text-sm text-[#8b5e3c]">
                Trang <b>{page}</b> / <b>{totalPages}</b>
              </span>

              <button
                disabled={page >= totalPages}
                onClick={() => setPage(page + 1)}
                className={`px-3 py-1 rounded border ${
                  page >= totalPages
                    ? "text-gray-300 border-gray-200 cursor-not-allowed"
                    : "text-[#8b5e3c] border-[#f1e4da] hover:bg-[#faf8f6]"
                }`}
              >
                Trang sau »
              </button>
            </div>
          </div>
        </>
      )}

      {/* POPUP SỬA NGƯỜI DÙNG */}
      {editUser && (
        <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-30 z-50">
          <div className="bg-white w-96 p-6 rounded-lg shadow-lg">

            <h3 className="text-lg font-semibold mb-4">
              Chỉnh sửa người dùng
            </h3>

            <label className="block mb-2">Tên</label>
            <input
              type="text"
              className="w-full border mb-4 p-2 rounded"
              value={editName}
              onChange={(e) => setEditName(e.target.value)}
            />

            <label className="block mb-2">Vai trò</label>
            <select
              className="w-full border mb-4 p-2 rounded"
              value={editRole}
              onChange={(e) => setEditRole(e.target.value)}
            >
              <option value="user">Người dùng</option>
              <option value="admin">Quản trị viên</option>
            </select>

            <div className="flex justify-end gap-3">
              <button
                className="px-4 py-2 bg-gray-200 rounded"
                onClick={() => setEditUser(null)}
              >
                Hủy
              </button>

              <button
                className="px-4 py-2 bg-[#e06c7f] text-white rounded"
                onClick={handleUpdate}
              >
                Lưu
              </button>
            </div>

          </div>
        </div>
      )}

    </div>
  );
};

export default AdminUsers;
